use crate::types::{DecideInput, DecideOutput};

fn realcompare(a: f64, b: f64) -> &'static str {
    if a == b {
        return "EQ";
    }
    let abs_a = a.abs();
    let abs_b = b.abs();
    let max_ab = if abs_a > abs_b { abs_a } else { abs_b };
    if max_ab == 0.0 {
        return "EQ";
    }
    let diff = (a - b).abs();
    if diff <= 1e-5 * max_ab {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    (dx * dx + dy * dy).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    let cross = (x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1);
    0.5 * cross.abs()
}

fn min_circle_radius_3pts(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    let d12 = dist(x1, y1, x2, y2);
    let d23 = dist(x2, y2, x3, y3);
    let d31 = dist(x3, y3, x1, y1);

    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if realcompare(area, 0.0) == "EQ" {
        // Collinear: radius is half of the longest side
        let mut max_side = d12;
        if realcompare(d23, max_side) == "GT" {
            max_side = d23;
        }
        if realcompare(d31, max_side) == "GT" {
            max_side = d31;
        }
        return max_side / 2.0;
    }

    // Determine longest side
    let sides = [d23, d31, d12];
    let mut max_idx = 0;
    for i in 1..3 {
        if realcompare(sides[i], sides[max_idx]) == "GT" {
            max_idx = i;
        }
    }
    let (max_side, other1, other2) = match max_idx {
        0 => (sides[0], sides[1], sides[2]),
        1 => (sides[1], sides[0], sides[2]),
        _ => (sides[2], sides[0], sides[1]),
    };

    // Check for obtuse or right triangle
    let sum_sq = other1 * other1 + other2 * other2;
    let max_sq = max_side * max_side;
    if realcompare(sum_sq, max_sq) != "GT" {
        return max_side / 2.0;
    }

    // Acute triangle: circumradius
    (d12 * d23 * d31) / (4.0 * area)
}

fn angle_at_vertex(x1: f64, y1: f64, xv: f64, yv: f64, x3: f64, y3: f64) -> Option<f64> {
    let v1x = x1 - xv;
    let v1y = y1 - yv;
    let v2x = x3 - xv;
    let v2y = y3 - yv;
    let len1 = (v1x * v1x + v1y * v1y).sqrt();
    let len2 = (v2x * v2x + v2y * v2y).sqrt();
    if realcompare(len1, 0.0) == "EQ" || realcompare(len2, 0.0) == "EQ" {
        return None;
    }
    let mut cos_theta = (v1x * v2x + v1y * v2y) / (len1 * len2);
    if realcompare(cos_theta, 1.0) == "GT" {
        cos_theta = 1.0;
    } else if realcompare(cos_theta, -1.0) == "LT" {
        cos_theta = -1.0;
    }
    Some(cos_theta.acos())
}

fn quadrant(x: f64, y: f64) -> usize {
    if realcompare(x, 0.0) != "LT" && realcompare(y, 0.0) != "LT" {
        0 // I
    } else if realcompare(x, 0.0) == "LT" && realcompare(y, 0.0) != "LT" {
        1 // II
    } else if realcompare(x, 0.0) != "GT" && realcompare(y, 0.0) == "LT" {
        2 // III
    } else {
        3 // IV
    }
}

fn distance_point_to_line(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    let denom = (dx * dx + dy * dy).sqrt();
    if realcompare(denom, 0.0) == "EQ" {
        return dist(px, py, x1, y1);
    }
    ((dy * px - dx * py + x2 * y1 - y2 * x1).abs()) / denom
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let n = input.numpoints;
    let p = &input.parameters;
    let x = &input.x;
    let y = &input.y;

    let mut cmv = vec![false; 15];

    // LIC 1
    if n >= 2 {
        for i in 0..(n - 1) {
            let d = dist(x[i], y[i], x[i + 1], y[i + 1]);
            if realcompare(d, p.length1) == "GT" {
                cmv[0] = true;
                break;
            }
        }
    }

    // LIC 2
    if n >= 3 {
        for i in 0..(n - 2) {
            let r = min_circle_radius_3pts(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
            if realcompare(r, p.radius1) == "GT" {
                cmv[1] = true;
                break;
            }
        }
    }

    // LIC 3
    if n >= 3 {
        for i in 0..(n - 2) {
            if let Some(angle) = angle_at_vertex(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]) {
                let lower = std::f64::consts::PI - p.epsilon;
                let upper = std::f64::consts::PI + p.epsilon;
                if realcompare(angle, lower) == "LT" || realcompare(angle, upper) == "GT" {
                    cmv[2] = true;
                    break;
                }
            }
        }
    }

    // LIC 4
    if n >= 3 {
        for i in 0..(n - 2) {
            let area = triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
            if realcompare(area, p.area1) == "GT" {
                cmv[3] = true;
                break;
            }
        }
    }

    // LIC 5
    if n >= p.q_pts && p.q_pts >= 2 {
        let q = p.q_pts;
        for start in 0..=(n - q) {
            let mut seen = [false; 4];
            for i in start..(start + q) {
                let idx = quadrant(x[i], y[i]);
                seen[idx] = true;
            }
            let count = seen.iter().filter(|v| **v).count();
            if count > p.quads {
                cmv[4] = true;
                break;
            }
        }
    }

    // LIC 6
    if n >= 2 {
        for i in 0..(n - 1) {
            let diff = x[i + 1] - x[i];
            if realcompare(diff, 0.0) == "LT" {
                cmv[5] = true;
                break;
            }
        }
    }

    // LIC 7
    if n >= 3 && n >= p.n_pts {
        let m = p.n_pts;
        for start in 0..=(n - m) {
            let first = start;
            let last = start + m - 1;
            let x1 = x[first];
            let y1 = y[first];
            let x2 = x[last];
            let y2 = y[last];
            if realcompare(dist(x1, y1, x2, y2), 0.0) == "EQ" {
                for i in (first + 1)..last {
                    let d = dist(x1, y1, x[i], y[i]);
                    if realcompare(d, p.dist) == "GT" {
                        cmv[6] = true;
                        break;
                    }
                }
            } else {
                for i in (first + 1)..last {
                    let d = distance_point_to_line(x[i], y[i], x1, y1, x2, y2);
                    if realcompare(d, p.dist) == "GT" {
                        cmv[6] = true;
                        break;
                    }
                }
            }
            if cmv[6] {
                break;
            }
        }
    }

    // LIC 8
    if n >= 3 && p.k_pts >= 1 {
        for i in 0..(n - p.k_pts - 1) {
            let j = i + p.k_pts + 1;
            let d = dist(x[i], y[i], x[j], y[j]);
            if realcompare(d, p.length1) == "GT" {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9
    if n >= 5 && p.a_pts >= 1 && p.b_pts >= 1 && p.a_pts + p.b_pts <= n - 3 {
        for i in 0..(n - p.a_pts - p.b_pts - 2) {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            let r = min_circle_radius_3pts(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(r, p.radius1) == "GT" {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10
    if n >= 5 && p.c_pts >= 1 && p.d_pts >= 1 && p.c_pts + p.d_pts <= n - 3 {
        for i in 0..(n - p.c_pts - p.d_pts - 2) {
            let j = i + p.c_pts + 1;
            let k = j + p.d_pts + 1;
            if let Some(angle) = angle_at_vertex(x[i], y[i], x[j], y[j], x[k], y[k]) {
                let lower = std::f64::consts::PI - p.epsilon;
                let upper = std::f64::consts::PI + p.epsilon;
                if realcompare(angle, lower) == "LT" || realcompare(angle, upper) == "GT" {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11
    if n >= 5 && p.e_pts >= 1 && p.f_pts >= 1 && p.e_pts + p.f_pts <= n - 3 {
        for i in 0..(n - p.e_pts - p.f_pts - 2) {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(area, p.area1) == "GT" {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12
    if n >= 3 && p.g_pts >= 1 {
        for i in 0..(n - p.g_pts - 1) {
            let j = i + p.g_pts + 1;
            let diff = x[j] - x[i];
            if realcompare(diff, 0.0) == "LT" {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13
    if n >= 3 && p.k_pts >= 1 {
        let mut cond1 = false;
        let mut cond2 = false;
        for i in 0..(n - p.k_pts - 1) {
            let j = i + p.k_pts + 1;
            let d = dist(x[i], y[i], x[j], y[j]);
            if realcompare(d, p.length1) == "GT" {
                cond1 = true;
            }
            if realcompare(d, p.length2) == "LT" {
                cond2 = true;
            }
            if cond1 && cond2 {
                break;
            }
        }
        cmv[12] = cond1 && cond2;
    }

    // LIC 14
    if n >= 5 && p.a_pts >= 1 && p.b_pts >= 1 && p.a_pts + p.b_pts <= n - 3 {
        let mut cond1 = false;
        let mut cond2 = false;
        for i in 0..(n - p.a_pts - p.b_pts - 2) {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            let r = min_circle_radius_3pts(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(r, p.radius1) == "GT" {
                cond1 = true;
            }
            if realcompare(r, p.radius2) != "GT" {
                cond2 = true;
            }
            if cond1 && cond2 {
                break;
            }
        }
        cmv[13] = cond1 && cond2;
    }

    // LIC 15
    if n >= 5 && p.e_pts >= 1 && p.f_pts >= 1 && p.e_pts + p.f_pts <= n - 3 {
        let mut cond1 = false;
        let mut cond2 = false;
        for i in 0..(n - p.e_pts - p.f_pts - 2) {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(area, p.area1) == "GT" {
                cond1 = true;
            }
            if realcompare(area, p.area2) == "LT" {
                cond2 = true;
            }
            if cond1 && cond2 {
                break;
            }
        }
        cmv[14] = cond1 && cond2;
    }

    // PUM
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }
    for i in 0..15 {
        for j in (i + 1)..15 {
            let entry = match input.lcm[i][j].as_str() {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => false,
            };
            pum[i][j] = entry;
            pum[j][i] = entry;
        }
    }

    // FUV
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }

    let launch = fuv.iter().all(|v| *v);

    DecideOutput { cmv, pum, fuv, launch }
}
